// ============================================================
// NODE: Validate Incoming Request
// Checks that all required fields are present before
// the pipeline begins. Returns {valid, errors} object.
// ============================================================

const body = $input.first().json;

const errors = [];

// Required top-level fields
if (!body.user_id)   errors.push('Missing required field: user_id');
if (!body.resume_id) errors.push('Missing required field: resume_id');

// Type validation
if (body.user_id && typeof body.user_id !== 'string')
  errors.push('user_id must be a string (UUID)');
if (body.resume_id && typeof body.resume_id !== 'string')
  errors.push('resume_id must be a string (UUID)');

// Optional search preferences — validate if present
if (body.preferences) {
  const prefs = body.preferences;
  const validRemote = ['remote', 'hybrid', 'onsite', 'any'];
  if (prefs.remote_preference && !validRemote.includes(prefs.remote_preference)) {
    errors.push(`preferences.remote_preference must be one of: ${validRemote.join(', ')}`);
  }
  if (prefs.salary_min !== undefined && typeof prefs.salary_min !== 'number') {
    errors.push('preferences.salary_min must be a number');
  }
}

// Resume safety — prevent oversized payloads
if (body.resume_text && body.resume_text.length > 100000) {
  errors.push('resume_text exceeds maximum length of 100,000 characters');
}

return [{
  json: {
    valid: errors.length === 0,
    errors,
    original_body: body
  }
}];

// ============================================================
// NODE: Initialize Execution Context
// Creates the canonical ExecutionContext object that flows
// through every agent in the pipeline.
// IMPORTANT: This context is the single source of truth.
// Every agent reads from it and writes back to it.
// ============================================================

const { v4: uuidv4 } = require('crypto');
const body = $input.first().json.original_body;

// Generate a unique execution ID for full pipeline tracing
const execution_id = `exec_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
const started_at = new Date().toISOString();

// Build the canonical Execution Context
const execution_context = {
  // Identity
  execution_id,
  pipeline_version: $env.PIPELINE_VERSION || '1.0.0',
  started_at,

  // Request payload
  user_id: body.user_id,
  resume_id: body.resume_id,

  // Optional resume text (if passed directly)
  resume_text: body.resume_text || null,

  // User preferences (with defaults)
  preferences: {
    target_roles:       body.preferences?.target_roles       || [],
    target_industries:  body.preferences?.target_industries  || [],
    preferred_locations:body.preferences?.preferred_locations|| [],
    remote_preference:  body.preferences?.remote_preference  || 'any',
    salary_min:         body.preferences?.salary_min         || 0,
    max_jobs:           body.preferences?.max_jobs           || parseInt($env.PIPELINE_MAX_JOBS) || 20,
    cover_letter_top_n: body.preferences?.cover_letter_top_n || parseInt($env.PIPELINE_COVER_LETTER_TOP_N) || 5,
    posted_within_days: body.preferences?.posted_within_days || 7
  },

  // Resume from a checkpoint (used for partial recovery)
  resume_from_agent: body.resume_from_agent || null,

  // Pipeline tracking
  agents_completed: [],
  agents_failed: [],
  agents_skipped: [],

  // Accumulated results (updated after each agent completes)
  results: {
    resume_profile:       null,
    career_goals:         null,
    jobs_raw:             [],
    internships_raw:      [],
    jobs_merged:          [],
    jobs_quality_scored:  [],
    jobs_ghost_filtered:  [],
    jobs_scam_filtered:   [],
    jobs_deduplicated:    [],
    companies:            {},
    ats_reports:          [],
    resume_versions:      [],
    cover_letters:        [],
    application_packets:  []
  },

  // Resource consumption tracking
  meta: {
    total_tokens_input:  0,
    total_tokens_output: 0,
    total_tokens_used:   0,
    total_cost_usd:      0,
    total_duration_ms:   0,
    agent_timings:       {}
  },

  // Error and warning log
  errors:   [],
  warnings: []
};

console.log(`[MASTER] Pipeline started | execution_id=${execution_id} | user_id=${body.user_id} | resume_id=${body.resume_id}`);

return [{ json: { execution_context } }];

// ============================================================
// NODE: Absorb Resume Intelligence Output
// Merges agent output back into the execution context
// and handles partial failure gracefully.
// ============================================================

const agentOutput = $input.first().json;
const ctx = agentOutput.execution_context;
const meta = agentOutput.agent_meta || {};

// Track timing
if (meta.duration_ms) {
  ctx.meta.agent_timings['resume_intelligence'] = meta.duration_ms;
  ctx.meta.total_duration_ms += meta.duration_ms;
}

// Track token usage
if (meta.tokens_total) {
  ctx.meta.total_tokens_used += meta.tokens_total;
  ctx.meta.total_tokens_input  += (meta.tokens_input  || 0);
  ctx.meta.total_tokens_output += (meta.tokens_output || 0);
}

// Absorb result or log failure
if (agentOutput.status === 'success' || agentOutput.status === 'partial') {
  ctx.results.resume_profile = agentOutput.resume_profile;
  ctx.agents_completed.push('resume_intelligence');
  console.log(`[MASTER] resume_intelligence completed | score=${agentOutput.resume_profile?.parse_confidence || 0}%`);
} else {
  ctx.agents_failed.push('resume_intelligence');
  ctx.errors.push({ agent: 'resume_intelligence', error: agentOutput.error || 'Unknown error', timestamp: new Date().toISOString() });
  console.error(`[MASTER] resume_intelligence FAILED | error=${agentOutput.error}`);
}

return [{ json: { execution_context: ctx, resume_failed: !ctx.results.resume_profile } }];

// ============================================================
// NODE: Absorb Career Goal Output
// ============================================================
const agentOutput = $input.first().json;
const ctx = agentOutput.execution_context;
const meta = agentOutput.agent_meta || {};

if (meta.duration_ms) { ctx.meta.agent_timings['career_goal'] = meta.duration_ms; ctx.meta.total_duration_ms += meta.duration_ms; }
if (meta.tokens_total) { ctx.meta.total_tokens_used += meta.tokens_total; }

if (agentOutput.status !== 'failed') {
  ctx.results.career_goals = agentOutput.career_goals;
  ctx.agents_completed.push('career_goal');
  console.log(`[MASTER] career_goal completed | primary_role=${agentOutput.career_goals?.primary_role}`);
} else {
  ctx.agents_failed.push('career_goal');
  ctx.warnings.push({ agent: 'career_goal', warning: 'Career goal detection failed — using user preferences as fallback', timestamp: new Date().toISOString() });
  // FALLBACK: Use user preferences directly as career goals
  ctx.results.career_goals = {
    primary_role: ctx.preferences.target_roles[0] || 'Software Engineer',
    secondary_roles: ctx.preferences.target_roles.slice(1),
    target_industries: ctx.preferences.target_industries,
    search_keywords: ctx.preferences.target_roles,
    excluded_keywords: [],
    location_strategy: { preferred: ctx.preferences.preferred_locations, remote: ctx.preferences.remote_preference }
  };
}

return [{ json: { execution_context: ctx } }];

// ============================================================
// NODE: Merge & Deduplicate Raw Search Results
// Combines job + internship results from both parallel
// branches into a single deduplicated list.
// ============================================================

const allInputs = $input.all();

// Extract the two branches (job search + internship search)
let jobsCtx       = null;
let internshipsCtx = null;
let ctx            = null;

for (const item of allInputs) {
  const d = item.json;
  if (!ctx) ctx = d.execution_context;
  if (d.search_type === 'jobs')        { jobsCtx       = d; }
  if (d.search_type === 'internships') { internshipsCtx = d; }
}

// Use whichever context is latest (both should be same base)
if (!ctx) ctx = allInputs[0]?.json?.execution_context;

// Absorb job search results
const jobs = jobsCtx?.jobs || [];
const internships = internshipsCtx?.internships || [];

if (jobsCtx) {
  ctx.results.jobs_raw = jobs;
  ctx.agents_completed.push('job_search');
  console.log(`[MASTER] job_search completed | found=${jobs.length} jobs`);
}
if (internshipsCtx) {
  ctx.results.internships_raw = internships;
  ctx.agents_completed.push('internship_search');
  console.log(`[MASTER] internship_search completed | found=${internships.length} internships`);
}

// Combine all listings under a single array for downstream agents
// Each listing has a 'type' field: 'job' or 'internship'
const allListings = [
  ...jobs.map(j => ({ ...j, listing_type: 'job' })),
  ...internships.map(i => ({ ...i, listing_type: 'internship' }))
];

ctx.results.jobs_merged = allListings;

console.log(`[MASTER] search merge complete | total=${allListings.length} listings`);

return [{ json: { execution_context: ctx } }];

// ============================================================
// NODE: Apply Quality Filters
// Combines ghost + scam detection results and applies
// configurable thresholds to filter listings.
// ============================================================

const allInputs = $input.all();
let ctx = null;
let ghostData = null;
let scamData  = null;

for (const item of allInputs) {
  const d = item.json;
  if (!ctx) ctx = d.execution_context;
  if (d.filter_type === 'ghost') ghostData = d;
  if (d.filter_type === 'scam')  scamData  = d;
}

if (!ctx) ctx = allInputs[0]?.json?.execution_context;

const ghostThreshold = parseInt($env.PIPELINE_GHOST_THRESHOLD) || 70;
const scamThreshold  = parseInt($env.PIPELINE_SCAM_THRESHOLD)  || 70;

// Build a score map by job_id
const ghostScores = {};
const scamScores  = {};

(ghostData?.ghost_scores || []).forEach(g => { ghostScores[g.listing_id] = g.ghost_score; });
(scamData?.scam_scores   || []).forEach(s => { scamScores[s.listing_id]  = s.scam_score;  });

// Apply filters to merged listings
const listings = ctx.results.jobs_merged || [];

const filtered = listings.filter(l => {
  const ghostScore = ghostScores[l.listing_id] ?? 0;
  const scamScore  = scamScores[l.listing_id]  ?? 0;
  const isGhost    = ghostScore >= ghostThreshold;
  const isScam     = scamScore  >= scamThreshold;

  // Annotate listing
  l.ghost_score = ghostScore;
  l.scam_score  = scamScore;
  l.is_ghost    = isGhost;
  l.is_scam     = isScam;

  return !isGhost && !isScam;
});

ctx.results.jobs_ghost_filtered = filtered;
ctx.results.jobs_scam_filtered  = filtered;
ctx.agents_completed.push('ghost_detection', 'scam_detection');

console.log(`[MASTER] quality filters applied | before=${listings.length} after=${filtered.length} (removed ${listings.length - filtered.length})`);

return [{ json: { execution_context: ctx } }];

// ============================================================
// NODE: Build Final Pipeline Response
// Assembles the canonical API response from the
// execution context. Calculates total runtime.
// ============================================================

const allInputs = $input.all();
let ctx = null;
for (const item of allInputs) {
  if (item.json?.execution_context) { ctx = item.json.execution_context; break; }
}

const ended_at      = new Date().toISOString();
const started_ms    = new Date(ctx.started_at).getTime();
const ended_ms      = Date.now();
const wall_time_ms  = ended_ms - started_ms;

ctx.meta.wall_time_ms  = wall_time_ms;
ctx.meta.ended_at      = ended_at;
ctx.pipeline_status    = ctx.agents_failed.length === 0 ? 'success' : 'partial_success';

console.log(`[MASTER] Pipeline COMPLETE | id=${ctx.execution_id} | status=${ctx.pipeline_status} | time=${wall_time_ms}ms | tokens=${ctx.meta.total_tokens_used}`);

const response = {
  success:         true,
  execution_id:    ctx.execution_id,
  status:          ctx.pipeline_status,
  started_at:      ctx.started_at,
  ended_at,
  wall_time_ms,
  agents_completed: ctx.agents_completed,
  agents_failed:    ctx.agents_failed,
  agents_skipped:   ctx.agents_skipped,
  summary: {
    jobs_found:          ctx.results.jobs_merged?.length        || 0,
    jobs_after_filter:   ctx.results.jobs_deduplicated?.length  || 0,
    ats_reports_created: ctx.results.ats_reports?.length        || 0,
    applications_ready:  ctx.results.application_packets?.length|| 0
  },
  meta: ctx.meta,
  errors:   ctx.errors,
  warnings: ctx.warnings
};

return [{ json: { response, execution_context: ctx } }];

// ============================================================
// NODE: Global Error Handler
// Catches any unhandled errors in the pipeline.
// Logs them and triggers an error notification.
// ============================================================

const error = $input.first().json;

console.error(`[MASTER][ERROR] Global error caught | workflow=${error.workflow?.name} | node=${error.node?.name} | message=${error.execution?.error?.message}`);

const errorPayload = {
  error_type: 'pipeline_error',
  workflow:   error.workflow?.name  || 'Master Workflow',
  node:       error.node?.name      || 'Unknown Node',
  message:    error.execution?.error?.message || 'Unknown error',
  stack:      error.execution?.error?.stack   || null,
  timestamp:  new Date().toISOString(),
  execution_id: error.execution?.id || null
};

return [{ json: errorPayload }];
